String t(String key) {
  final e = _dict[key];
  if (e == null) return key;
  return e[Http.lang] ?? e['zh'] ?? key;
}

// 带占位符的翻译:tp('epsAll', {'n': 12}) → 全12集 / 12 EP
String tp(String key, Map<String, Object> vars) {
  var s = t(key);
  vars.forEach((k, v) => s = s.replaceAll('{$k}', '$v'));
  return s;
}
